create table if not exists public.curriculum_packs(id uuid primary key default gen_random_uuid(),year_code text not null,title text not null,version text default '1.0',active boolean default true,created_at timestamptz default now());create table if not exists public.curriculum_units(id uuid primary key default gen_random_uuid(),pack_id uuid references public.curriculum_packs(id) on delete cascade,unit_code text not null,title text not null,sort_order int default 0,metadata jsonb default '{}'::jsonb);create table if not exists public.micro_games(id uuid primary key default gen_random_uuid(),game_code text unique not null,title text not null,config jsonb default '{}'::jsonb,active boolean default true);create table if not exists public.student_game_sessions(id uuid primary key default gen_random_uuid(),player_name text,class_code text,year_code text,unit_code text,game_code text,score int default 0,coins int default 0,details jsonb default '{}'::jsonb,created_at timestamptz default now());select 'Super Maths Platform v7 schema ready' as status;